const items = $input.all();
const tasks = items.map((item) => item?.json?.Tasks).flat().filter(task => task);
const chatIds = items.map((item) => item?.json["Chat ID"]).flat().filter(id => id);
const fileNames = items.map((item) => item?.json?.File_name).flat().filter(name => name);
const usernames = items.map((item) => item?.json?.Username).flat().filter(user => user);
const tasksString = tasks.join('\n---\n');

return [{
  Tasks: tasksString,
  "Chat ID": chatIds,
  "File_name": fileNames,
  "Username": usernames
}];

