const usernames = items.map((item) => item?.json?.Username).flat().filter(user => user);
const tasksString = tasks.join('\n---\n');

return [{
  Tasks: tasksString,
  "Chat ID": chatIds,
  "File_name": fileNames,
  "Username": usernames
}];

// Получаем массив данных из поля task_content
const taskContentArray = $input.first().json.task_content;

// Проверяем, что данные получены и это массив
if (!taskContentArray || !Array.isArray(taskContentArray)) {
  console.log('Поле task_content не найдено или не является массивом');
  return [{
    Tasks: ''
  }];
}

console.log(`Найдено элементов в массиве: ${taskContentArray.length}`);

// Объединяем все элементы массива в одну строку с разделителем ---
const combinedTasks = taskContentArray.join('\n---\n');

console.log(`Длина объединенной строки: ${combinedTasks.length}`);

return [{
  Tasks: combinedTasks
}];

