  timeZone: 'Europe/Moscow',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
};

// Получаем полную строку в формате "ДД.ММ.ГГГГ, ЧЧ:ММ:СС"
